var query = $.input.leadName;
if ($.input.companyName) query += ' ' + $.input.companyName;
query += ' professional background';
return { query: query };

var results = $.steps.researchLead.response.results || [];
var researchText = '';
results.forEach(function(r, i) {
  researchText += 'SOURCE ' + (i + 1) + ': ' + (r.title || '') + '\n';
  researchText += 'URL: ' + (r.url || '') + '\n';
  researchText += (r.text || '').slice(0, 1500) + '\n\n';
});
return { researchText: researchText, sourceCount: results.length };

var data = $.steps.compileResearch.output;
var prompt = 'You are a sales intelligence analyst and email copywriter. Analyze the following research about a lead and generate enriched data plus a personalized outreach email.

';
prompt += 'LEAD: ' + $.input.leadName + '
';
prompt += 'EMAIL: ' + $.input.leadEmail + '
';
if ($.input.companyName) prompt += 'COMPANY: ' + $.input.companyName + '
';
prompt += 'OUTREACH PURPOSE: ' + $.input.outreachPurpose + '

';
prompt += 'RESEARCH DATA (' + data.sourceCount + ' sources):
' + data.researchText + '
';
prompt += 'INSTRUCTIONS:
';
prompt += '- Extract: title/role, company, industry, interests, recent activity
';
prompt += '- Score lead quality 1-100
';
prompt += '- Write a personalized, non-spammy outreach email
';
prompt += '- Reference specific details from research to show authenticity
';
prompt += '- Keep email under 150 words

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "enrichedProfile": {
';
prompt += '    "name": "...",
';
prompt += '    "title": "...",
';
prompt += '    "company": "...",
';
prompt += '    "industry": "...",
';
prompt += '    "interests": ["..."],
';
prompt += '    "recentActivity": "...",
';
prompt += '    "leadScore": 75
';
prompt += '  },
';
prompt += '  "outreachEmail": {
';
prompt += '    "subject": "Email subject line",
';
prompt += '    "body": "HTML email body"
';
prompt += '  }
';
prompt += '}';
return { prompt: prompt };

let raw = $.steps.aiEnrich.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { enrichedProfile: { name: $.input.leadName, title: '', company: $.input.companyName || '', industry: '', interests: [], recentActivity: '', leadScore: 0 }, outreachEmail: { subject: 'Quick question', body: '<p>' + raw.slice(0, 500) + '</p>' } }; }

var ai = $.steps.parseAI.output;
var profile = ai.enrichedProfile || {};
var date = new Date().toISOString().split('T')[0];
var sheetData = [{
  'Name': profile.name || $.input.leadName,
  'Email': $.input.leadEmail,
  'Title': profile.title || '',
  'Company': profile.company || $.input.companyName || '',
  'Industry': profile.industry || '',
  'Interests': (profile.interests || []).join(', '),
  'Recent Activity': (profile.recentActivity || '').slice(0, 200),
  'Lead Score': profile.leadScore || '',
  'Outreach Status': 'Email Sent',
  'Date Enriched': date
}];
return { sheetData: sheetData, date: date };

var ai = $.steps.parseAI.output;
var email = ai.outreachEmail || {};
var body = email.body || '';
if (body.length < 20) {
  body = '<p>Hi ' + $.input.leadName.split(' ')[0] + ',</p><p>' + $.input.outreachPurpose + '</p>';
}
return { subject: email.subject || 'Quick question', body: body.slice(0, 1900) };
